		}		
		cout << endl;
	}
}

void matrixDoixung(int a[][100], int n,int  m) {
	int b[100][100];
	for (int i=0; i < n; i++) {
		for (int j = 0; j < m; j++) {
			b[i][m-j-1] = a[i][j];
		}		
	}

	printMatrix(b, n, m);
